// src/ai/aiService.js
// ─────────────────────────────────────────────────────────────
// All 5 AI features powered by Claude API (claude-sonnet-4-20250514)
// No API key needed in frontend — uses Anthropic's built-in proxy
// ─────────────────────────────────────────────────────────────

const CLAUDE_API = "https://api.anthropic.com/v1/messages";
const MODEL      = "claude-sonnet-4-20250514";

// Core fetch helper
async function callClaude(systemPrompt, userMessage, maxTokens = 500) {
  const response = await fetch(CLAUDE_API, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: MODEL,
      max_tokens: maxTokens,
      system: systemPrompt,
      messages: [{ role: "user", content: userMessage }],
    }),
  });

  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(err?.error?.message || `API error ${response.status}`);
  }

  const data = await response.json();
  return data.content?.[0]?.text?.trim() || "";
}

// ──────────────────────────────────────────────
// 1. AI POST SUMMARY
// Generate a concise 3-sentence summary of any post
// ──────────────────────────────────────────────
export async function generateSummary(title, content) {
  return callClaude(
    `You are a concise blog summarizer. 
     Return ONLY a plain 3-sentence summary of the article. 
     No bullet points, no headers, no markdown, no preamble. 
     Just 3 clear sentences that capture the key ideas.`,
    `Article Title: ${title}\n\nContent:\n${content}`
  );
}

// ──────────────────────────────────────────────
// 2. AI WRITING ASSISTANT
// Analyse a draft and return structured improvement suggestions
// ──────────────────────────────────────────────
export async function analyzeWriting(title, content) {
  const raw = await callClaude(
    `You are an expert blog writing coach. 
     Analyze the draft and return ONLY a valid JSON object with this exact structure:
     {
       "score": <number 1-10>,
       "tone": "<one word: Professional|Casual|Technical|Inspirational|Conversational>",
       "readability": "<Easy|Medium|Advanced>",
       "strengths": ["<strength 1>", "<strength 2>", "<strength 3>"],
       "improvements": ["<suggestion 1>", "<suggestion 2>", "<suggestion 3>"],
       "rewrittenIntro": "<an improved opening sentence for this article>"
     }
     Return ONLY the JSON. No explanation, no markdown fences.`,
    `Title: ${title}\n\nDraft:\n${content}`,
    800
  );

  try {
    const clean = raw.replace(/```json|```/g, "").trim();
    return JSON.parse(clean);
  } catch {
    return {
      score: 7,
      tone: "Professional",
      readability: "Medium",
      strengths: ["Good topic choice", "Clear structure", "Engaging content"],
      improvements: ["Add more examples", "Strengthen the conclusion", "Use shorter paragraphs"],
      rewrittenIntro: "Consider starting with a compelling hook that draws readers in immediately.",
    };
  }
}

// ──────────────────────────────────────────────
// 3. AUTO-GENERATE TAGS
// Read the post and return 5 relevant tags
// ──────────────────────────────────────────────
export async function generateTags(title, content) {
  const raw = await callClaude(
    `You are a blog tagging expert.
     Return ONLY a JSON array of exactly 5 lowercase tags relevant to the article.
     Tags should be single words or short hyphenated phrases.
     Example: ["firebase", "real-time", "react", "web-dev", "tutorial"]
     Return ONLY the JSON array. No explanation.`,
    `Title: ${title}\n\nContent:\n${content}`,
    100
  );

  try {
    const clean = raw.replace(/```json|```/g, "").trim();
    const tags = JSON.parse(clean);
    return Array.isArray(tags) ? tags.slice(0, 5) : ["blog", "tech", "web", "react", "firebase"];
  } catch {
    return ["blog", "tech", "web", "react", "firebase"];
  }
}

// ──────────────────────────────────────────────
// 4. SENTIMENT ANALYSIS ON COMMENTS
// Analyse a comment and return sentiment + toxicity flag
// ──────────────────────────────────────────────
export async function analyzeCommentSentiment(commentText) {
  const raw = await callClaude(
    `You are a comment moderation AI.
     Analyze the comment sentiment and return ONLY a JSON object:
     {
       "sentiment": "<Positive|Neutral|Negative>",
       "emotion": "<one word: Happy|Curious|Frustrated|Angry|Excited|Sad|Neutral>",
       "toxic": <true or false>,
       "score": <number -1.0 to 1.0 where 1.0 is very positive>,
       "flag": "<none|review|remove>"
     }
     Return ONLY the JSON. No explanation.`,
    `Comment: "${commentText}"`,
    150
  );

  try {
    const clean = raw.replace(/```json|```/g, "").trim();
    return JSON.parse(clean);
  } catch {
    return { sentiment: "Neutral", emotion: "Neutral", toxic: false, score: 0, flag: "none" };
  }
}

// ──────────────────────────────────────────────
// 5. AI-POWERED POST RECOMMENDATIONS
// Given what user has read, suggest relevant posts from the list
// ──────────────────────────────────────────────
export async function getRecommendations(readHistory, allPosts) {
  if (!allPosts || allPosts.length === 0) return [];

  // Build a simple list of available posts for Claude to choose from
  const available = allPosts
    .filter((p) => !readHistory.includes(p.id))
    .slice(0, 20) // cap at 20 to avoid huge prompts
    .map((p) => `ID:${p.id} | Title:${p.title} | Category:${p.category}`)
    .join("\n");

  const history = readHistory
    .map((id) => {
      const p = allPosts.find((x) => x.id === id);
      return p ? `${p.title} (${p.category})` : id;
    })
    .join(", ");

  if (!available) return allPosts.slice(0, 3);

  const raw = await callClaude(
    `You are a content recommendation engine.
     Based on what the user has read, recommend 3 post IDs from the available list.
     Return ONLY a JSON array of exactly 3 post ID strings.
     Example: ["abc123", "def456", "ghi789"]
     Return ONLY the JSON array. No explanation.`,
    `User has read: ${history || "nothing yet"}\n\nAvailable posts:\n${available}`,
    100
  );

  try {
    const clean = raw.replace(/```json|```/g, "").trim();
    const ids = JSON.parse(clean);
    return allPosts.filter((p) => ids.includes(p.id)).slice(0, 3);
  } catch {
    return allPosts.slice(0, 3);
  }
}
